(self.webpackChunk=self.webpackChunk||[]).push([[166],{9854:(e,s,n)=>{"use strict";n.r(s),n.d(s,{data:()=>a});const a={key:"v-b0e7af4e",path:"/linux/centos.html",title:"Centos 常规操作",lang:"en-US",frontmatter:{title:"Centos 常规操作"},excerpt:"",headers:[{level:2,title:"修改SSH默认端口",slug:"修改ssh默认端口",children:[{level:3,title:"1 修改端口",slug:"_1-修改端口",children:[]},{level:3,title:"2 防火墙放行",slug:"_2-防火墙放行",children:[]},{level:3,title:"3 SELinux放行",slug:"_3-selinux放行",children:[]},{level:3,title:"4 重启SSH服务",slug:"_4-重启ssh服务",children:[]}]},{level:2,title:"BBR",slug:"bbr",children:[{level:3,title:"开启BBR",slug:"开启bbr",children:[]}]},{level:2,title:"修改IP",slug:"修改ip",children:[]},{level:2,title:"修改主机名",slug:"修改主机名",children:[]},{level:2,title:"更改yum源与更新系统",slug:"更改yum源与更新系统",children:[]},{level:2,title:"dockerDNS",slug:"dockerdns",children:[{level:3,title:"宿主机防火墙开启伪装IP功能",slug:"宿主机防火墙开启伪装ip功能",children:[]},{level:3,title:"trusted zone",slug:"trusted-zone",children:[]}]}],filePathRelative:"linux/centos.md",git:{updatedTime:1626154667e3,contributors:[]}}},6255:(e,s,n)=>{"use strict";n.r(s),n.d(s,{default:()=>r});const a=(0,n(6252).uE)('<h2 id="修改ssh默认端口" tabindex="-1"><a class="header-anchor" href="#修改ssh默认端口" aria-hidden="true">#</a> 修改SSH默认端口</h2><h3 id="_1-修改端口" tabindex="-1"><a class="header-anchor" href="#_1-修改端口" aria-hidden="true">#</a> 1 修改端口</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code> vi /etc/ssh/sshd_config\n #找到Port XX 修改为自己想要的端口\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div> <br><h3 id="_2-防火墙放行" tabindex="-1"><a class="header-anchor" href="#_2-防火墙放行" aria-hidden="true">#</a> 2 防火墙放行</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>#修改XXX为上面修改后端口\nfirewall-cmd --zone=public --add-port=XXX/tcp --permanent\n# 刷新防火墙规则\nfirewall-cmd --reload\n#查看是否生效\nfirewall-cmd --zone=public --query-port=XXX/tcp\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br></div></div> <br><h3 id="_3-selinux放行" tabindex="-1"><a class="header-anchor" href="#_3-selinux放行" aria-hidden="true">#</a> 3 SELinux放行</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>#检查semanage是否安装\nrpm -qa |grep policycoreutils-python\n   #安装\n   yum install policycoreutils-python\n#查看当前SSH允许端口\nsemanage port -l |grep ssh\n#添加新端口\nsemanage port -a -t ssh_port_t -p tcp XXX\n#检查是否添加成功\nsemanage port -l |grep ssh\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br><span class="line-number">8</span><br><span class="line-number">9</span><br><span class="line-number">10</span><br></div></div><br><h3 id="_4-重启ssh服务" tabindex="-1"><a class="header-anchor" href="#_4-重启ssh服务" aria-hidden="true">#</a> 4 重启SSH服务</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>systemctl restart sshd.service\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><br><br><br><br><h2 id="bbr" tabindex="-1"><a class="header-anchor" href="#bbr" aria-hidden="true">#</a> BBR</h2><h3 id="开启bbr" tabindex="-1"><a class="header-anchor" href="#开启bbr" aria-hidden="true">#</a> 开启BBR</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>#centos\ncurl -O https://raw.githubusercontent.com/teddysun/across/master/bbr.sh &amp;&amp; sh bbr.sh\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><h2 id="修改ip" tabindex="-1"><a class="header-anchor" href="#修改ip" aria-hidden="true">#</a> 修改IP</h2><ul><li><p>方式一 nmtui 调出修改窗口</p></li><li><p>方式二 cd /etc/sysconfig/network-scripts/ 修改相关网卡文件</p></li></ul><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>      IPADDR=192.168.0.230 #静态IP\n      GATEWAY=192.168.0.1 #默认网关\n      NETMASK=255.255.255.0 #子网掩码\n      DNS1=192.168.0.1 #DNS 配置\n      DNS2=8.8.8.8 #谷歌地址\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><p>重启网卡：service network restart</p><h2 id="修改主机名" tabindex="-1"><a class="header-anchor" href="#修改主机名" aria-hidden="true">#</a> 修改主机名</h2><p>在CentOS7中，有三种定义的主机名:</p><p>静态的（Static hostname） “静态”主机名也称为内核主机名，是系统在启动时从/etc/hostname自动初始化的主机名。</p><p>瞬态的（Tansient hostname） “瞬态”主机名是在系统运行时临时分配的主机名，例如，通过DHCP或mDNS服务器分配。</p><p>灵活的（Pretty hostname） “灵活”主机名也有人叫做“别名”主机名。 “灵活”主机名则允许使用自由形式（包括特殊/空白字符）的主机名，以展示给终端用户（如xh01@f5）。 “静态”主机名和“瞬态”主机名都遵从作为互联网域名同样的字符限制规则。</p><p>在CentOS 7中，有个叫hostnamectl的命令行工具，它允许你查看或修改与主机名相关的配置。</p><p><span style="color:red;">一旦修改了静态主机名，/etc/hostname 将被自动更新。然而，/etc/hosts 不会更新以保存所做的修改，所以你每次在修改主机名后一定要手动更新/etc/hosts，之后再重启CentOS 7。否则系统再启动时会很慢。</span></p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>//永久性的修改主机名称，重启后能保持修改后的。\nhostnamectl set-hostname xxx    \n\n//删除hostname\nhostnamectl set-hostname &quot;&quot;\nhostnamectl set-hostname &quot;&quot; --static\nhostnamectl set-hostname &quot;&quot; --pretty\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br><span class="line-number">6</span><br><span class="line-number">7</span><br></div></div><h2 id="更改yum源与更新系统" tabindex="-1"><a class="header-anchor" href="#更改yum源与更新系统" aria-hidden="true">#</a> 更改yum源与更新系统</h2><p>备份</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>mv /etc/yum.repos.d/CentOS-Base.repo /etc/yum.repos.d/CentOS-Base.repo.backup\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>下载yum源配置文件，放入/etc/yum.repos.d/</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>wget -O /etc/yum.repos.d/CentOS-Base.repo http://mirrors.aliyun.com/repo/Centos-8.repo\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>运行yum makecache生成缓存</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>yum makecache\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><p>更新系统</p><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>yum -y update\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br></div></div><h2 id="dockerdns" tabindex="-1"><a class="header-anchor" href="#dockerdns" aria-hidden="true">#</a> dockerDNS</h2><blockquote><p>docker 无法访问DNS服务</p></blockquote><h3 id="宿主机防火墙开启伪装ip功能" tabindex="-1"><a class="header-anchor" href="#宿主机防火墙开启伪装ip功能" aria-hidden="true">#</a> 宿主机防火墙开启伪装IP功能</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>firewall-cmd --zone=public --add-masquerade --permanent\nfirewall-cmd --reload\nsystemctl restart firewalld\nsystemctl restart docker\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br></div></div><h3 id="trusted-zone" tabindex="-1"><a class="header-anchor" href="#trusted-zone" aria-hidden="true">#</a> trusted zone</h3><div class="language-text ext-text line-numbers-mode"><pre class="language-text"><code>firewall-cmd --permanent --zone=trusted --add-interface=docker0\nfirewall-cmd --reload\n</code></pre><div class="line-numbers"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div>',48),r={render:function(e,s){return a}}}}]);